mapper.select:
SELECT m_idx, name AS username, email, password, reg_date AS regDate, active,
       linked_customer AS linkedCustomer
FROM member_t WHERE m_idx = #{m_idx}

mapper.update:
UPDATE member_t
SET name = #{username}
WHERE m_idx = #{m_idx}

UPDATE customer_t
SET name  = #{username},
    phone = #{phone}
WHERE c_idx = #{linkedCustomer}
